68	func SessionIndexShardName(t time.Time) string {
69		if t.IsZero() {
70			t = time.Now().UTC()
71		}
72		return fmt.Sprintf("sessions-%04d-%02d.jsonl", t.UTC().Year(), t.UTC().Month())
73	}
74	
75	func SessionIndexShardPath(logDir string, t time.Time) string {
76		return filepath.Join(SessionIndexDir(logDir), SessionIndexShardName(t))
77	}
