79	func ProjectIDForPath(path string) string {
80		canonical, err := filepath.Abs(path)
81		if err == nil {
82			path = canonical
83		}
84		h := sha256.Sum256([]byte(path))
85		return fmt.Sprintf("proj-%x", h[:4])
86	}
