88	func AppendSessionIndex(logDir string, entry SessionIndexEntry, now time.Time) error {
89		if logDir == "" {
90			return nil
91		}
92		if now.IsZero() {
93			now = time.Now().UTC()
94		}
95		if entry.ID == "" {
96			entry.ID = genSessionID()
97		}
98		if entry.StartedAt.IsZero() {
99			entry.StartedAt = now.UTC()
100		}
101		if entry.EndedAt.IsZero() && entry.DurationMS > 0 {
102			entry.EndedAt = entry.StartedAt.Add(time.Duration(entry.DurationMS) * time.Millisecond).UTC()
103		}
104		if entry.Outcome == "" {
105			if entry.ExitCode == 0 && entry.Detail == "" {
106				entry.Outcome = "success"
107			} else {
108				entry.Outcome = "failure"
109			}
110		}
111		if err := os.MkdirAll(SessionIndexDir(logDir), 0o755); err != nil {
112			return err
113		}
114		data, err := json.Marshal(entry)
115		if err != nil {
116			return err
117		}
118		path := SessionIndexShardPath(logDir, now.UTC())
119		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
120		if err != nil {
121			return err
122		}
123		defer f.Close()
124		_, err = fmt.Fprintf(f, "%s\n", data)
125		return err
126	}
