258	func ReadSessionIndex(logDir string, q SessionIndexQuery) ([]SessionIndexEntry, error) {
259		files, err := SessionIndexShardFiles(logDir, q)
260		if err != nil {
261			return nil, err
262		}
263		var out []SessionIndexEntry
264		if q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
265			out, err = readRecentSessionIndexFiles(files, 1000)
266		} else {
267			out, err = readSessionIndexFiles(files, q)
268		}
269		if err != nil {
270			return nil, err
271		}
272		if len(out) == 0 && q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
273			files, err = SessionIndexShardFiles(logDir, SessionIndexQuery{})
274			if err != nil {
275				return nil, err
276			}
277			out, err = readSessionIndexFiles(files, q)
278			if err != nil {
279				return nil, err
280			}
281		}
282		sort.Slice(out, func(i, j int) bool {
283			return out[i].StartedAt.After(out[j].StartedAt)
284		})
285		return out, nil
286	}
