288	func readRecentSessionIndexFiles(files []string, perFile int) ([]SessionIndexEntry, error) {
289		var out []SessionIndexEntry
290		for _, file := range files {
291			data, err := os.ReadFile(file)
292			if os.IsNotExist(err) {
293				continue
294			}
295			if err != nil {
296				return nil, err
297			}
298			lines := bytes.Split(bytes.TrimSpace(data), []byte{'\n'})
299			start := 0
300			if perFile > 0 && len(lines) > perFile {
301				start = len(lines) - perFile
302			}
303			for _, line := range lines[start:] {
304				if len(bytes.TrimSpace(line)) == 0 {
305					continue
306				}
307				var entry SessionIndexEntry
308				if err := json.Unmarshal(line, &entry); err == nil {
309					out = append(out, entry)
310				}
311			}
312		}
313		return out, nil
314	}
