316	func readSessionIndexFiles(files []string, q SessionIndexQuery) ([]SessionIndexEntry, error) {
317		var out []SessionIndexEntry
318		for _, file := range files {
319			err := ForEachJSONL[SessionIndexEntry](file, func(entry SessionIndexEntry) error {
320				if !sessionIndexEntryInRange(entry, q) {
321					return nil
322				}
323				out = append(out, entry)
324				return nil
325			})
326			if err != nil {
327				return nil, err
328			}
329		}
330		return out, nil
331	}
