333	func FindSessionIndex(logDir, id string) (SessionIndexEntry, bool, error) {
334		files, err := SessionIndexShardFiles(logDir, SessionIndexQuery{})
335		if err != nil {
336			return SessionIndexEntry{}, false, err
337		}
338		for _, file := range files {
339			var found SessionIndexEntry
340			ok := false
341			err := ForEachJSONL[SessionIndexEntry](file, func(entry SessionIndexEntry) error {
342				if entry.ID == id {
343					found = entry
344					ok = true
345					return fmt.Errorf("found")
346				}
347				return nil
348			})
349			if ok {
350				return found, true, nil
351			}
352			if err != nil && err.Error() != "found" {
353				return SessionIndexEntry{}, false, err
354			}
355		}
356		return SessionIndexEntry{}, false, nil
357	}
