359	func SessionIndexShardFiles(logDir string, q SessionIndexQuery) ([]string, error) {
360		dir := SessionIndexDir(logDir)
361		entries, err := os.ReadDir(dir)
362		if os.IsNotExist(err) {
363			return nil, nil
364		}
365		if err != nil {
366			return nil, err
367		}
368		var files []string
369		for _, ent := range entries {
370			if ent.IsDir() {
371				continue
372			}
373			name := ent.Name()
374			if !strings.HasPrefix(name, "sessions-") || !strings.HasSuffix(name, ".jsonl") {
375				continue
376			}
377			if !sessionShardIntersects(name, q) {
378				continue
379			}
380			files = append(files, filepath.Join(dir, name))
381		}
382		sort.Sort(sort.Reverse(sort.StringSlice(files)))
383		return files, nil
384	}
