386	func ReindexLegacySessions(projectRoot, logDir string) (int, error) {
387		legacyPath := filepath.Join(logDir, LegacySessionsFileName)
388		readPath := legacyPath
389		if _, err := os.Stat(readPath); os.IsNotExist(err) {
390			readPath = filepath.Join(logDir, LegacySessionsRenameName)
391			if _, legacyErr := os.Stat(readPath); os.IsNotExist(legacyErr) {
392				return 0, nil
393			} else if legacyErr != nil {
394				return 0, legacyErr
395			}
396		} else if err != nil {
397			return 0, err
398		}
399	
400		existing, err := existingSessionIndexIDs(logDir)
401		if err != nil {
402			return 0, err
403		}
404		count := 0
405		err = ForEachJSONL[SessionEntry](readPath, func(entry SessionEntry) error {
406			if entry.ID == "" {
407				return nil
408			}
409			if _, ok := existing[entry.ID]; ok {
410				return nil
411			}
412			idx := SessionIndexEntryFromLegacy(projectRoot, entry)
413			if err := AppendSessionIndex(logDir, idx, entry.Timestamp.UTC()); err != nil {
414				return err
415			}
416			existing[entry.ID] = struct{}{}
417			count++
418			return nil
419		})
420		if err != nil {
421			return count, err
422		}
423		if readPath == legacyPath {
424			renamed := filepath.Join(logDir, LegacySessionsRenameName)
425			if _, err := os.Stat(renamed); os.IsNotExist(err) {
426				if err := os.Rename(legacyPath, renamed); err != nil {
427					return count, err
428				}
429			}
430		}
431		return count, nil
432	}
