434	func LoadSessionBodies(projectRoot string, entry SessionIndexEntry) SessionBodies {
435		var bodies SessionBodies
436		if entry.BundlePath != "" {
437			bundleDir := resolveProjectPath(projectRoot, entry.BundlePath)
438			if data, err := os.ReadFile(filepath.Join(bundleDir, "prompt.md")); err == nil {
439				bodies.Prompt = string(data)
440			}
441			if data, err := os.ReadFile(filepath.Join(bundleDir, "result.json")); err == nil {
442				bodies.Response, bodies.Stderr = bodiesFromResultJSON(data)
443			}
444		}
445		if entry.NativeLogRef != "" {
446			nativePath := resolveProjectPath(projectRoot, entry.NativeLogRef)
447			resp, stderr := bodiesFromNativeLog(nativePath)
448			if bodies.Response == "" {
449				bodies.Response = resp
450			}
451			if bodies.Stderr == "" {
452				bodies.Stderr = stderr
453			}
454		}
455		if bodies.Stderr == "" && entry.Detail != "" && entry.Outcome == "failure" {
456			bodies.Stderr = entry.Detail
457		}
458		return bodies
459	}
