499	func sessionIndexEntryInRange(entry SessionIndexEntry, q SessionIndexQuery) bool {
500		if q.StartedAfter != nil && entry.StartedAt.Before(*q.StartedAfter) {
501			return false
502		}
503		if q.StartedBefore != nil && !entry.StartedAt.Before(*q.StartedBefore) {
504			return false
505		}
506		return true
507	}
