509	func sessionShardIntersects(name string, q SessionIndexQuery) bool {
510		month, ok := sessionShardMonth(name)
511		if !ok {
512			return false
513		}
514		next := month.AddDate(0, 1, 0)
515		if q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
516			now := time.Now().UTC()
517			current := time.Date(now.Year(), now.Month(), 1, 0, 0, 0, 0, time.UTC)
518			previous := current.AddDate(0, -1, 0)
519			return month.Equal(current) || month.Equal(previous)
520		}
521		if q.StartedAfter != nil && !next.After(*q.StartedAfter) {
522			return false
523		}
524		if q.StartedBefore != nil && !month.Before(*q.StartedBefore) {
525			return false
526		}
527		return true
528	}
