530	func sessionShardMonth(name string) (time.Time, bool) {
531		if len(name) != len("sessions-2006-01.jsonl") {
532			return time.Time{}, false
533		}
534		month, err := time.Parse("2006-01", strings.TrimSuffix(strings.TrimPrefix(name, "sessions-"), ".jsonl"))
535		if err != nil {
536			return time.Time{}, false
537		}
538		return month.UTC(), true
539	}
