561	func relativizePath(root, path string) string {
562		if path == "" {
563			return ""
564		}
565		if root != "" && filepath.IsAbs(path) {
566			if rel, err := filepath.Rel(root, path); err == nil && !strings.HasPrefix(rel, "..") {
567				return filepath.ToSlash(rel)
568			}
569		}
570		return filepath.ToSlash(path)
571	}
