580	func bodiesFromResultJSON(data []byte) (string, string) {
581		var raw map[string]any
582		if err := json.Unmarshal(data, &raw); err != nil {
583			return "", ""
584		}
585		response := firstString(raw, "response", "output", "final_text", "finalText", "detail")
586		stderr := firstString(raw, "stderr", "error")
587		return response, stderr
588	}
