590	func bodiesFromNativeLog(path string) (string, string) {
591		f, err := os.Open(path)
592		if err != nil {
593			return "", ""
594		}
595		defer f.Close()
596		var response, stderr string
597		scanner := bufio.NewScanner(f)
598		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
599		for scanner.Scan() {
600			var raw map[string]any
601			if err := json.Unmarshal(scanner.Bytes(), &raw); err != nil {
602				continue
603			}
604			if s := firstNestedString(raw, []string{"data", "final_text"}, []string{"data", "finalText"}, []string{"final_text"}, []string{"finalText"}); s != "" {
605				response = s
606			}
607			if s := firstNestedString(raw, []string{"data", "error"}, []string{"error"}, []string{"stderr"}); s != "" {
608				stderr = s
609			}
610		}
611		return response, stderr
612	}
613	
614	func firstString(raw map[string]any, keys ...string) string {
615		for _, key := range keys {
616			if s, ok := raw[key].(string); ok && s != "" {
617				return s
618			}
619		}
620		return ""
621	}
622	
623	func firstNestedString(raw map[string]any, paths ...[]string) string {
624		for _, path := range paths {
625			cur := any(raw)
626			for _, key := range path {
627				m, ok := cur.(map[string]any)
628				if !ok {
629					cur = nil
630					break
631				}
632				cur = m[key]
633			}
634			if s, ok := cur.(string); ok && s != "" {
635				return s
636			}
637		}
638		return ""
639	}
