14	func TestSessionIndexWritesMonthlyShards(t *testing.T) {
15		logDir := filepath.Join(t.TempDir(), ".ddx", "agent-logs")
16		jan := time.Date(2026, 1, 31, 23, 59, 0, 0, time.UTC)
