337	// ValidateForExecuteLoopViaService is the production replacement for
338	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
339	// will pick at claim time). When harness is specified it confirms the harness
340	// exists in the service registry and (when model is set) attempts a
341	// ResolveRoute pre-flight.
342	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
343		if harnessName == "" {
344			return nil
345		}
346		if ctx == nil {
347			ctx = context.Background()
348		}
349		svc, err := NewServiceFromWorkDir(workDir)
350		if err != nil {
351			return fmt.Errorf("agent: build service: %w", err)
352		}
353		infos, err := svc.ListHarnesses(ctx)
354		if err != nil {
355			return fmt.Errorf("agent: list harnesses: %w", err)
356		}
357		found := false
358		for _, info := range infos {
359			if info.Name == harnessName {
360				found = true
361				if !info.Available {
362					return fmt.Errorf("agent: harness %s not available", harnessName)
363				}
364				break
365			}
366		}
367		if !found {
368			return fmt.Errorf("agent: unknown harness: %s", harnessName)
369		}
370	
371		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
372		// model is provided and provider/model-ref are not set.
373		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
374			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
375				Model:    model,
376				Harness:  harnessName,
377				ModelRef: modelRef,
378				Provider: provider,
379			}); err != nil {
380				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
381			}
382		}
383		return nil
384	}
