662	func agentSessionFromIndex(projectID string, e agent.SessionIndexEntry) *ddxgraphql.AgentSession {
663		sess := &ddxgraphql.AgentSession{
664			ID:         e.ID,
665			ProjectID:  projectID,
666			Harness:    e.Harness,
667			Model:      e.Model,
668			Effort:     e.Effort,
669			DurationMs: e.DurationMS,
670			StartedAt:  e.StartedAt.UTC().Format(time.RFC3339),
671		}
672	
673		// Derive status and outcome from exit code / error.
674		if e.ExitCode != 0 || e.Outcome == "failure" {
675			sess.Status = "failed"
676			outcome := "failure"
677			sess.Outcome = &outcome
678			if e.Detail != "" {
679				sess.Detail = &e.Detail
680			}
681		} else {
682			sess.Status = "completed"
683			outcome := "success"
684			sess.Outcome = &outcome
685		}
686	
687		// EndedAt = StartedAt + duration.
688		if !e.EndedAt.IsZero() {
689			endedAt := e.EndedAt.UTC().Format(time.RFC3339)
690			sess.EndedAt = &endedAt
691		} else if e.DurationMS > 0 {
692			endedAt := e.StartedAt.Add(time.Duration(e.DurationMS) * time.Millisecond).UTC().Format(time.RFC3339)
693			sess.EndedAt = &endedAt
694		}
695	
696		if e.CostUSD > 0 {
697			sess.Cost = &e.CostUSD
698		}
699	
700		// Token breakdown.
701		if e.InputTokens > 0 || e.OutputTokens > 0 || e.Tokens > 0 {
702			prompt := e.InputTokens
703			completion := e.OutputTokens
704			total := e.Tokens
705			sess.Tokens = &ddxgraphql.TokenUsage{
706				Prompt:     &prompt,
707				Completion: &completion,
708				Total:      &total,
709			}
710		}
711	
712		if e.BeadID != "" {
713			sess.BeadID = &e.BeadID
714		}
715		if e.NativeLogRef != "" {
716			sess.StdoutPath = &e.NativeLogRef
717		}
718		if e.BaseRev != "" {
719			sess.BaseRev = &e.BaseRev
720		}
721		if e.ResultRev != "" {
722			sess.ResultRev = &e.ResultRev
723		}
724		return sess
725	}
