120	// stablePageBounds computes the [startIdx, endIdx) slice window using stable
121	// ID-based cursors. ids must contain the stable key for each edge in order.
122	func stablePageBounds(ids []string, after, before *string) (startIdx, endIdx int) {
123		startIdx = 0
124		endIdx = len(ids)
125		if after != nil {
126			if afterID, ok := decodeStableCursor(*after); ok {
127				for i, id := range ids {
128					if id == afterID {
129						startIdx = i + 1
130						break
131					}
132				}
133			}
134		}
135		if before != nil {
136			if beforeID, ok := decodeStableCursor(*before); ok {
137				for i, id := range ids {
138					if id == beforeID {
139						endIdx = i
140						break
141					}
142				}
143			}
144		}
145		if startIdx > endIdx {
146			startIdx = endIdx
147		}
148		return startIdx, endIdx
149	}
