239		all := make([]*ExecutionRunEdge, len(runs))
240		ids := make([]string, len(runs))
241		for i, r := range runs {
242			all[i] = &ExecutionRunEdge{Node: r, Cursor: encodeStableCursor(r.ID)}
243			ids[i] = r.ID
244		}
245		startIdx, endIdx := stablePageBounds(ids, after, before)
246		slice := all[startIdx:endIdx]
247		truncByFirst, truncByLast := false, false
248		if first != nil && *first >= 0 && *first < len(slice) {
249			slice = slice[:*first]
250			truncByFirst = true
251		}
252		if last != nil && *last >= 0 && *last < len(slice) {
253			slice = slice[len(slice)-*last:]
254			truncByLast = true
255		}
256		pageInfo := &PageInfo{
257			HasPreviousPage: startIdx > 0 || truncByLast,
258			HasNextPage:     endIdx < len(all) || truncByFirst,
259		}
260		if len(slice) > 0 {
261			pageInfo.StartCursor = &slice[0].Cursor
262			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
263		}
264		return &ExecutionRunConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
265	}
